        "starterCode": "function matchRoute(pattern, url) {\n  const patternParts = pattern.split('/');\n  const urlParts = url.split('/');\n  const params = {};\n  \n  if (patternParts.length !== urlParts.___) return null;\n  \n  for (let i = 0; i < patternParts.length; i++) {\n    if (patternParts[i].startsWith('___')) {\n      params[patternParts[i].slice(1)] = urlParts[i];\n    } else if (patternParts[i] !== urlParts[i]) {\n      return null;\n    }\n  }\n  return params;\n}\n\nconsole.log(matchRoute('/users/:id', '/users/42'));\nconsole.log(matchRoute('/posts/:postId/comments/:commentId', '/posts/5/comments/12'));",
        "solution": "function matchRoute(pattern, url) {\n  const patternParts = pattern.split('/');\n  const urlParts = url.split('/');\n  const params = {};\n  \n  if (patternParts.length !== urlParts.length) return null;\n  \n  for (let i = 0; i < patternParts.length; i++) {\n    if (patternParts[i].startsWith(':')) {\n      params[patternParts[i].slice(1)] = urlParts[i];\n    } else if (patternParts[i] !== urlParts[i]) {\n      return null;\n    }\n  }\n  return params;\n}\n\nconsole.log(matchRoute('/users/:id', '/users/42'));\nconsole.log(matchRoute('/posts/:postId/comments/:commentId', '/posts/5/comments/12'));",
