        "solution": "class CrudAPI {\n  constructor() { this.items = []; this.nextId = 1; }\n  \n  create(data) {\n    const item = { id: this.nextId++, ...data };\n    this.items.push(item);\n    return item;\n  }\n  readAll() { return this.items; }\n  readOne(id) { return this.items.find(i => i.id === id); }\n  update(id, data) {\n    const item = this.readOne(id);\n    if (item) Object.assign(item, data);\n    return item;\n  }\n  delete(id) {\n    this.items = this.items.filter(i => i.id !== id);\n  }\n}\n\nconst api = new CrudAPI();\nconsole.log(api.create({name: 'Laptop', price: 999}));\nconsole.log(api.create({name: 'Mouse', price: 29}));\nconsole.log(api.readAll());\napi.update(1, {price: 899});\nconsole.log(api.readOne(1));\napi.delete(2);\nconsole.log(api.readAll());",
